            'LEC': (220, 0, 0),
            'NOR': (255, 135, 0),
        }

    @patch('src.f1_data.get_driver_colors')
    @patch('src.f1_data._get_wdc_standings')
    def test_basic_race_results(self, mock_wdc, mock_colors, mock_session, mock_driver_colors):
        mock_colors.return_value = mock_driver_colors
        mock_wdc.return_value = {'VER': 1, 'PER': 2, 'SAI': 3, 'LEC': 4}

