        assert p1['points'] == 25
        assert p1['fastest_lap'] is True
        assert p1['wdc_position'] == 1
        assert p1['race_time_secs'] is not None

    @patch('src.f1_data.get_driver_colors')
    @patch('src.f1_data._get_wdc_standings')
    def test_race_time_seconds(self, mock_wdc, mock_colors, mock_session, mock_driver_colors):
        mock_colors.return_value = mock_driver_colors
        mock_wdc.return_value = {}

        results = get_race_results(mock_session)

