        mock_ergast = Mock()
        mock_ergast_class.return_value = mock_ergast

        standings_df = pd.DataFrame({
            'driverCode': ['VER', 'PER', 'LEC'],
            'position': [1, 2, 3]
        })
        mock_standings = Mock()
        mock_standings.content = [standings_df]
        mock_ergast.get_driver_standings.return_value = mock_standings

