        mock_response.json.return_value = {
            'MRData': {
                'StandingsTable': {
                    'StandingsLists': [{
                        'DriverStandings': [
                            {'position': '1', 'Driver': {'code': 'VER'}},
                            {'position': '2', 'Driver': {'code': 'PER'}},
                        ]
                    }]
                }
            }
        }
        mock_requests.return_value = mock_response

        result = _get_wdc_standings(mock_session)

        assert result == {'VER': 1, 'PER': 2}

    @patch('src.f1_data.Ergast')
    @patch('requests.get')
    def test_both_methods_fail_returns_empty(self, mock_requests, mock_ergast_class, mock_session):
        mock_ergast_class.side_effect = Exception("fastf1 failed")
        mock_requests.side_effect = Exception("requests failed")

        result = _get_wdc_standings(mock_session)

        assert result == {}


